var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후우, 고생했어. 치후유.","JPN":"ふう、お疲れ様。千冬。","ENG":"Phew. You did well, Chifuyu.","TWN":"呼，辛苦了，千冬。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님도 고생하셨습니다.","JPN":"当主もお疲れ様でした。","ENG":"As did you, my lady.","TWN":"堂主也辛苦了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"생각보다 수가 많군요. 그리고 이 침식체들에게서 신기한 것들이 나왔습니다.","JPN":"思ったより数が多いですね。それに、この侵食体からは不思議なものが出ました。","ENG":"There were more of them than I thought. And I found some peculiar things from these C.O.s.","TWN":"數量比想像中還多，而且這些侵蝕體的身上會冒出一些神奇的東西。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"붉은 돌, 노란색 보석, 이터니움을 양분삼아 자라는 식물……","JPN":"赤い石、黄色い宝石、エタニウムを栄養分にして育つ植物……","ENG":"Red stones, yellow gems, and plants that take up nutrients from Eternium...","TWN":"有紅色的石頭、黃色的寶石、還有以永恆之金為養分的植物……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"밖에서 보던 침식체들과는 사뭇 다르군요.","JPN":"外で見た侵食体とはまったく違いますね。","ENG":"They are different from the C.O.s we see outside.","TWN":"和在外面看到的侵蝕體有很大不同。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이게 카페 분들이 말한 재료인 걸까?","JPN":"これがカフェの方々が言っていた材料なのかしら。","ENG":"Could these be the materials they were talking about?","TWN":"這就是咖啡廳的人說的材料嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저는 그렇다고 생각합니다.","JPN":"そうだと思います。","ENG":"I think they are.","TWN":"我想應該是。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"음…… 어디선가 안 좋은 기운이 느껴지는데.","JPN":"うーん……どこからか良くない気配がするわ。","ENG":"Hmm... I feel some ominous energy from somewhere.","TWN":"嗯……某個地方傳來不好的氣味。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"아직 침식체가 남아 있는 걸까요?","JPN":"まだ侵食体が残っているのでしょうか。","ENG":"Are there more C.O.s remaining?","TWN":"還有侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…… 아무래도 더 위험한 게 남아 있는 것 같아.","JPN":"……どうやら、もっと危険なものが残ってるみたいよ。","ENG":"...It feels like there is something more dangerous.","TWN":"……看來還有更危險的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이 정도면 충분해. 슬슬 올라갈 준비를 하자고.","JPN":"このくらいあれば十分だ。そろそろ上がる準備をしよう。","ENG":"This should be enough. Let's get ready to head up.","TWN":"這些材料就夠了，我們上去吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"라우라 공. 잠시만 기다려주십시오.","JPN":"ラウラ殿。少々お待ちください。","ENG":"Dame Laura, wait a moment.","TWN":"蘿拉，先稍等一下。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"응? 꼬맹이는 왜 그렇게 바짝 긴장하고 있어?","JPN":"む？　どうしてそんなに緊迫した顔をしているのだ、ちびっ子？","ENG":"Hmm? Why do you look so tense, kid?","TWN":"嗯？你幹嘛這麼緊張？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"꽤 많은 수의 1, 2 종 침식체를 잡았는데도, 여전히 침식체의 기운이 느껴져요.","JPN":"かなりの数の第1、第2種侵食体を倒したはずなのに、まだ食体の気配が感じられるのです。","ENG":"We defeated numerous Category 1 and 2 C.O.s, but I still feel their energy.","TWN":"雖然我們已經消滅掉大量的1類和2類侵蝕體，還是能感受到侵蝕體的氣味。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그것도 아주 서늘하고, 차가운 기운이에요.","JPN":"それもとてもぞっとするような、冷たい気配です。","ENG":"And it is an extremely cold, chilling energy at that.","TWN":"而且感覺非常陰沉寒冷。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"서늘하고 차가운 기운이라…… 그런 느낌을 주는 재료가 있긴 하지만.","JPN":"ぞっとするような冷たい気配か……そういった感じの材料があるにはあるが。","ENG":"A cold and chilling energy... There is a type of material that gives off that energy.","TWN":"陰沉寒冷……有些材料會散發出那種感覺沒錯…"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이 녀석들한테는 그런 고급 재료가 나오지 않아.","JPN":"こいつらからはそういった高級材料は出ない。","ENG":"But these C.O.s don't have that kind of high-quality material.","TWN":"但這些傢伙不會有這麼高級的材料。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아무래도 3종인 것 같네. 조심해야겠어.","JPN":"どうやら第3種のようだな。気をつけよう。","ENG":"It must be a Category 3. We should be careful.","TWN":"看來是3類，大家小心。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님. 제 뒤로 오십시오. 제가 호위하겠습니다.","JPN":"当主。私の後ろに。護衛します。","ENG":"Stay behind me, my lady. I shall escort you.","TWN":"堂主，請到我後面。我來保護堂主。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"결계의 틈을 비집고 빠져나온 녀석인가?","JPN":"結界の隙間から出てきたのか？","ENG":"Did it squeeze out through the barrier's crack?","TWN":"是從結界的縫隙中溜出來的嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"마음 같아서는 위험하니 돌아가라고 하고 싶은데……","JPN":"危ないから帰れと言いたい気持ちは山々だが……","ENG":"I'd normally tell you to go back since it's dangerous, but...","TWN":"雖然我心裡的聲音告訴我，有危險快回去吧，但……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"위험 요소는 서둘러 탐색하고 그 규모를 판단해 제거하는 것이 옳습니다.","JPN":"危険要素は早めに探索して規模を把握し、除去するに越したことはありません。","ENG":"Potential threats should be instantly investigated and removed after analysis.","TWN":"但是盡快找出危險的來源，判斷規模後將其消滅才是正確的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님과 제가 있으니 오히려 절호의 기회가 아닌지요?","JPN":"当主と私がいますので、むしろ絶好のチャンスではありませんか？","ENG":"And what better time to do it than when Lady Nanahara and I are here?","TWN":"有堂主和我在，這反而是個好機會，不是嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐, 그건 그렇지. 침식체들을 무 썰듯 써는 걸 보면 3종 상대로도 잘 싸울 것 같고.","JPN":"まあ、それもそうだな。侵食体をバサバサ斬っていくところを見ると、第3種相手でも戦えそうだしな。","ENG":"I guess you're right. I think you'll do well against Category 3s, seeing how you carved through those C.O.s so easily.","TWN":"嗯，這倒是。看你們砍侵蝕體像切菜一樣，對付3類應該也沒問題。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희 자매가 앞장서겠습니다. 라우라 님. 좀 더 안쪽에서 침식체의 기운이 느껴져요.","JPN":"私たち姉妹が先陣を切りましょう、ラウラ様。さらに奥の方から侵食体の気配がします。","ENG":"My sister and I will walk ahead, Miss Laura. I can sense a C.O. somewhere deeper.","TWN":"蘿拉，我們姊妹會走在前面，到更裡面的地方感受一下侵蝕體的氣味吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"다치지 않는 게 최우선인 거 알지? 위험하다 싶으면 바로 돌아갈 거야.","JPN":"怪我しないことが最優先だ。危険だと思ったらすぐに退却だ。","ENG":"You know you should prioritize your safety, right? We're going right back if it seems dangerous.","TWN":"最重要的是，不要受傷，知道嗎？一旦有危險，就立刻掉頭。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"알겠습니다. 라우라 공. 그럼 움직이시죠.","JPN":"わかりました、ラウラ殿。それでは行きましょう。","ENG":"Acknowledged, Dame Laura. Let us go forward, then.","TWN":"好的，那麼蘿拉，我們就行動吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};